THOUGHT: Peeling the last iteration currently mutates or replaces the exit condition even when it has other in-loop users (like the header branch), leading to semantic changes (e.g., header branch becomes constant false) and miscompilation. A conservative fix is to avoid PeelLast when the latch exit condition has other users within the loop. I will add a guard in LoopUnrollPass.cpp before invoking peelLoop: if PeelLast is requested and the latch condition instruction has other in-loop users besides the latch branch, disable PeelLast to preserve semantics.

```bash
python3 - <<'PY'
import re
path="llvm/lib/Transforms/Scalar/LoopUnrollPass.cpp"
with open(path,'r') as f:
    s=f.read()
# Find the section where peelLoop is called (around PP.PeelCount usage)
anchor = "if (peelLoop(L, PP.PeelCount, PP.PeelLast, LI, &SE, DT, &AC, PreserveLCSSA,"
idx = s.find(anchor)
if idx == -1:
    print("Failed to locate peelLoop call")
    raise SystemExit(1)
# Insert guard code a bit before the peelLoop call within tryToUnrollLoop
insert_point = s.rfind('\n', 0, idx)
guard_code = r'''
    // Conservative guard: If peeling the last iteration and the latch condition
    // has other in-loop users besides the latch branch, disable PeelLast to avoid
    // mutating shared conditions and miscompilation.
    if (PP.PeelLast && PP.PeelCount == 1) {
      if (auto *LatchBr = dyn_cast<BranchInst>(L->getLoopLatch()->getTerminator())) {
        Value *Cond = LatchBr->getCondition();
        if (auto *CondI = dyn_cast<Instruction>(Cond)) {
          bool HasOtherInLoopUsers = false;
          for (const Use &U : CondI->uses()) {
            if (U.getUser() != LatchBr) {
              if (auto *UserI = dyn_cast<Instruction>(U.getUser())) {
                if (L->contains(UserI->getParent())) {
                  HasOtherInLoopUsers = true;
                  break;
                }
              }
            }
          }
          if (HasOtherInLoopUsers) {
            PP.PeelLast = false;
            PP.PeelCount = 0;
          }
        }
      }
    }
'''
# Insert guard_code at insert_point
s = s[:insert_point] + guard_code + s[insert_point:]
with open(path,'w') as f:
    f.write(s)
print("Inserted PeelLast guard to disable peeling when exit condition has other in-loop users.")
PY
```

